mapper.select:
select o.*,shopkeeper.shop_name as shopName, goods.name as goodsName,goods.price as goodsPrice,goods.pic as goodsPic,
address.name as addressName,address.phone as addressPhone,address.address as address,
user.name as username
from `order` as o
left join  shopkeeper on shopkeeper.id=o.shopkeeper_id
left join goods on goods.id=o.goods_id
left join address on address.id=o.address_id
left join user on user.id=o.user_id



        and o.order_no = #{orderNo}


        and o.shopkeeper_id = #{shopkeeperId}


        and o.user_id = #{userId}


        and o.status = #{status}


order by id desc

select type.name as typeName, SUM(o.num) as saleNum from `order` as o left join goods on o.goods_id=goods.id left join type on type.id =goods.type_id where goods.status='上架'
and o.shopkeeper_id = #{shopkeeperId}
group by type.name
